def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  // Sort edges by time in ascending order
  val sortedEdges = edges.sortBy(_.apply(2))

  // Initialize DSU (Disjoint Set Union) structure
  val parent = Array.fill(n.toInt)(0)
  val rank = Array.fill(n.toInt)(0)

  def find(u: Int): Int = {
    if (parent(u) != u) parent(u) = find(parent(u))
    parent(u)
  }

  def union(u: Int, v: Int): Boolean = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU == rootV) false
    else {
      if (rank(rootU) > rank(rootV)) {
        parent(rootV) = rootU
      } else if (rank(rootU) < rank(rootV)) {
        parent(rootU) = rootV
      } else {
        parent(rootV) = rootU
        rank(rootU) += 1
      }
      true
    }
  }

  // Initialize DSU
  for (i <- 0 until n.toInt) {
    parent(i) = i
    rank(i) = 0
  }

  // Track the number of connected components
  var components = n.toInt

  // Iterate through edges in sorted order
  for (edge <- sortedEdges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val time = edge(2)

    // If the nodes are in different sets, union them and decrease components
    if (union(u, v)) {
      components -= 1
    }

    // Check if we have at least k components
    if (components >= k) {
      return time
    }
  }

  // If we haven't found the answer, return the maximum time (or 0 if no edges)
  if (edges.nonEmpty) {
    edges.max(0).apply(2)
  } else {
    0
  }
}
